// Extract key information from transcript
const transcript = $input.first().json.content;
const isOnboarding = $input.first().json.isOnboarding;

// Rule-based extraction (simplified)
const lines = transcript.toLowerCase();

// Extract business hours
let startTime = '09:00';
let endTime = '18:00';
let days = ['Mon', 'Tue', 'Wed', 'Thu', 'Fri'];
let timezone = 'PST';

if (lines.includes('7 am')) startTime = '07:00';
if (lines.includes('8 am')) startTime = '08:00';
if (lines.includes('5 pm')) endTime = '17:00';
if (lines.includes('6 pm')) endTime = '18:00';

// Extract services
const services = [];
if (lines.includes('plumb')) services.push('Plumbing');
if (lines.includes('hvac') || lines.includes('ac') || lines.includes('heating')) services.push('HVAC');
if (lines.includes('it') || lines.includes('tech') || lines.includes('support')) services.push('IT Support');
if (lines.includes('medical') || lines.includes('clinic')) services.push('Medical');
if (lines.includes('property') || lines.includes('maintenance')) services.push('Property Management');
if (lines.includes('repair')) services.push('Repair');

if (services.length === 0) services.push('General Service');

// Extract emergency info
const emergencies = [];
if (lines.includes('outage') || lines.includes('no hot water')) emergencies.push('Utility Outage');
if (lines.includes('flood') || lines.includes('leak')) emergencies.push('Water Leak');
if (lines.includes('ac') && lines.includes('heat')) emergencies.push('AC Out in Heat');
if (lines.includes('chest pain') || lines.includes('breathing')) emergencies.push('Medical Emergency');
if (lines.includes('security') || lines.includes('breach')) emergencies.push('Security Breach');

// Determine account type
let accountType = 'general';
if (lines.includes('plumb')) accountType = 'plumbing';
if (lines.includes('medical') || lines.includes('clinic')) accountType = 'medical';
if (lines.includes('property')) accountType = 'property';
if (lines.includes('it') || lines.includes('tech')) accountType = 'it';

return {
  business_hours: { days, start: startTime, end: endTime, timezone },
  services_supported: services,
  emergency_definition: emergencies.length > 0 ? emergencies : ['Urgent Issue'],
  account_type: accountType,
  is_onboarding: isOnboarding
};

// Generate account memo JSON
const extracted = $input.first().json;
const accountId = $('file-watcher').first().json.accountId || 'unknown';
const companyName = $('file-watcher').first().json.companyName || 'Unknown Company';
const version = extracted.is_onboarding ? 'v2' : 'v1';

const accountMemo = {
  account_id: accountId,
  company_name: companyName,
  business_hours: extracted.business_hours,
  office_address: 'See account notes',
  services_supported: extracted.services_supported,
  emergency_definition: extracted.emergency_definition,
  emergency_routing_rules: ['Transfer to on-call', 'Notify via SMS'],
  non_emergency_routing_rules: ['Schedule callback', 'Create work order'],
  call_transfer_rules: {
    timeouts: '30s',
    retries: 2,
    fallback: 'Leave message and notify via SMS'
  },
  integration_constraints: [],
  after_hours_flow_summary: 'Greet, confirm emergency, collect info, attempt transfer, fallback to voicemail',
  office_hours_flow_summary: 'Greet, collect info, transfer to agent, confirm next steps',
  questions_or_unknowns: [],
  notes: `Generated from ${extracted.is_onboarding ? 'onboarding' : 'demo'} call`
};

return { account_memo: accountMemo, version };

// Generate Retell agent spec
const memo = $input.first().json.accountMemo;
const extracted = $('extract-info').first().json;

const agentSpec = {
  agent_name: `${memo.company_name.split(' ')[0]}Agent`,
  voice_style: 'basic',
  system_prompt: `You are an automated assistant for ${memo.company_name}. ` +
    `Business hours are ${memo.business_hours.days.join('-')} ${memo.business_hours.start} to ${memo.business_hours.end}. ` +
    'During business hours, greet the caller, collect name and number, determine the purpose, and route to the correct agent. ' +
    'After hours, confirm if emergency, collect name, number, address, attempt transfer, fallback to voicemail, assure quick follow-up.',
  key_variables: {
    timezone: memo.business_hours.timezone,
    business_hours: memo.business_hours,
    office_address: memo.office_address,
    emergency_routing_rules: memo.emergency_routing_rules,
    non_emergency_routing_rules: memo.non_emergency_routing_rules,
    services_supported: memo.services_supported
  },
  tool_invocation_placeholders: [],
  call_transfer_protocol: memo.call_transfer_rules,
  fallback_protocol_if_transfer_fails: 'Leave message and send SMS notification',
  version: $input.first().json.version
};

return { agent_spec: agentSpec };

// Generate changelog for v2 updates
const isV2 = $('generate-memo').first().json.version === 'v2';

if (!isV2) {
  return { skip: true };
}

const changelog = {
  account_id: $('file-watcher').first().json.accountId,
  version_from: 'v1',
  version_to: 'v2',
  changes: [
    {
      field: 'services_supported',
      description: 'Updated from onboarding call'
    }
  ],
  timestamp: new Date().toISOString(),
  notes: 'Generated from onboarding info'
};

return { changelog };
